func tokenOrgName(token model.AuthToken, memberships []model.Membership) string {
	if token.OrgID() == "" {
		return "—"
	}
	for _, m := range memberships {
		if m.OrgID() == token.OrgID() && m.Org() != nil {
			return m.Org().Name()
		}
	}
	return string(token.OrgID())
}

func tokenExpiry(token model.AuthToken) string {
	if token.ExpiresAt() == nil {
		return "—"
	}
	return token.ExpiresAt().Format("02/01/2006")
}

